def solve(numbers, target):
    left, right = 0, len(numbers) - 1
    while left <= right:
        middle = (left + right) // 2
        if numbers[middle] == target:
            return True
        if numbers[middle] < target:
            left = middle + 1
        else:
            right = middle - 1
    return False

